        ExpressionColumn l = (ExpressionColumn) left;
        if (filter != l.getTableFilter() || !TypeInfo.haveSameOrdering(l.getType(),
                ignoreCase ? TypeInfo.TYPE_VARCHAR_IGNORECASE : TypeInfo.TYPE_VARCHAR)) {
