    public Expression optimize(SessionLocal session) {
        TypeInfo typeInfo = TypeInfo.TYPE_UNKNOWN;
        operand = operand.optimize(session);
        boolean allConst = operand.isConstant();
        Value v = null;
        if (allConst) {
            v = operand.getValue(session);
        }
        TypeInfo operandType = operand.getType();
        for (SimpleWhen when = this.when; when != null; when = when.next) {
            Expression[] operands = when.operands;
            for (int i = 0; i < operands.length; i++) {
                Expression e = operands[i].optimize(session);
                if (!e.isWhenConditionOperand()) {
                    TypeInfo.checkComparable(operandType, e.getType());
                }
                if (allConst) {
                    if (e.isConstant()) {
                        if (e.getWhenValue(session, v)) {
                            return when.result.optimize(session);
                        }
                    } else {
                        allConst = false;
                    }
                }
                operands[i] = e;
            }
            when.result = when.result.optimize(session);
            typeInfo = combineTypes(typeInfo, when.result);
        }
        if (elseResult != null) {
            elseResult = elseResult.optimize(session);
            if (allConst) {
                return elseResult;
            }
            typeInfo = combineTypes(typeInfo, elseResult);
        } else if (allConst) {
            return ValueExpression.NULL;
        }
        if (typeInfo.getValueType() == Value.UNKNOWN) {
            typeInfo = TypeInfo.TYPE_VARCHAR;
        }
        type = typeInfo;
        return this;
    }

    public Expression optimize(SessionLocal session) {
        determineType(session);
        inlineArguments();
        if (type.getValueType() == Value.VARCHAR && session.getMode().treatEmptyStringsAsNull) {
            return new ConcatFunction(ConcatFunction.CONCAT, args).optimize(session);
        }
        int l = args.length;
        boolean allConst = true, anyConst = false;
        for (int i = 0; i < l; i++) {
            if (args[i].isConstant()) {
                anyConst = true;
            } else {
                allConst = false;
            }
        }
        if (allConst) {
            return TypedValueExpression.getTypedIfNull(getValue(session), type);
        }
        if (anyConst) {
            int offset = 0;
            for (int i = 0; i < l; i++) {
                Expression arg1 = args[i];
                if (arg1.isConstant()) {
                    Value v1 = arg1.getValue(session).convertTo(type, session);
                    if (v1 == ValueNull.INSTANCE) {
                        return TypedValueExpression.get(ValueNull.INSTANCE, type);
                    }
                    if (isEmpty(v1)) {
                        continue;
                    }
                    for (Expression arg2; i + 1 < l && (arg2 = args[i + 1]).isConstant(); i++) {
                        Value v2 = arg2.getValue(session).convertTo(type, session);
                        if (v2 == ValueNull.INSTANCE) {
                            return TypedValueExpression.get(ValueNull.INSTANCE, type);
                        }
                        if (!isEmpty(v2)) {
                            v1 = getValue(session, v1, v2);
                        }
                    }
                    arg1 = ValueExpression.get(v1);
                }
                args[offset++] = arg1;
            }
            if (offset == 1) {
                Expression arg = args[0];
                TypeInfo argType = arg.getType();
                if (TypeInfo.areSameTypes(type, argType)) {
                    return arg;
                }
                return new CastSpecification(arg, type);
            }
            argsCount = offset;
            doneWithParameters();
        }
        return this;
    }

